class Solution:
    def minSwapsCouples(self, row):
        n = len(row)
        parent = list(range(n // 2))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        groups = n // 2
        for i in range(0, n, 2):
            a = find(row[i] // 2)
            b = find(row[i + 1] // 2)
            if a != b:
                parent[a] = b
                groups -= 1
        return n // 2 - groups

